css:
@page { size: A4; margin: 10mm 15mm; }
body { 
    font-family: 'Helvetica', 'Arial', sans-serif; 
    color: #333; font-size: 10pt; 
    line-height: 1.4;
    margin: 0; padding: 0;
}
.clearfix { clear: both; }
.header { 
    display: flex; 
    justify-content: space-between; 
    align-items: center;
    border-bottom: 3px solid #247DBD; 
    padding-bottom: 10px; 
    margin-bottom: 15px; 
}
.header-left h1 { 
    margin: 0; color: #247DBD; font-size: 20pt; 
}
.header-left .company-desc { color: #666; font-size: 9pt; }
.header-right { 
    text-align: right; 
    font-size: 9pt; 
}
.invoice-title { 
    text-align: center; 
    margin: 10px 0; 
}
.invoice-title h2 { 
    margin: 0; 
    color: #247DBD; 
    text-transform: uppercase; 
    letter-spacing: 2px;
    font-size: 14pt;
    border: 2px solid #247DBD;
    display: inline-block;
    padding: 5px 20px;
}
.info-row { 
    display: flex; 
    justify-content: space-between; 
    margin: 10px 0; 
    padding: 8px 0;
    border-bottom: 1px dashed #ddd; 
}
.info-box { 
    width: 48%; 
}
.info-box h4 { 
    margin: 0 0 5px 0; 
    color: #247DBD; 
    font-size: 10pt;
    border-bottom: 1px solid #247DBD;
    padding-bottom: 3px;
}
.info-box p { margin: 2px 0; font-size: 9pt; }
table.items { 
    width: 100%; 
    border-collapse: collapse; 
    margin: 15px 0; 
    font-size: 9pt;
}
table.items thead th { 
    background: #247DBD; 
    color: white; 
    padding: 6px 4px; 
    text-align: left; 
    font-weight: bold;
    font-size: 8pt;
    text-transform: uppercase;
}
table.items tbody td { 
    padding: 4px; 
    border-bottom: 1px solid #ddd; 
    vertical-align: top;
}
table.items tbody tr:nth-child(even) { background: #f5f8fc; }
table.items .num { text-align: right; }
.totals { 
    float: right; 
    width: 280px; 
    margin-top: 10px; 
}
.totals table { width: 100%; }
.totals td { padding: 4px 6px; font-size: 9pt; }
.totals tr.total-row td { border-top: 2px solid #247DBD; }
.totals .grand-total { 
    font-weight: bold; 
    font-size: 12pt; 
    color: #247DBD; 
}
.totals .label-cell { text-align: left; }
.totals .value-cell { text-align: right; }
.footer { 
    position: fixed; 
    bottom: 0; 
    left: 0; right: 0;
    text-align: center; 
    font-size: 8pt; 
    color: #999; 
    border-top: 1px solid #ddd; 
    padding-top: 8px; 
}
.terms { 
    margin-top: 30px; 
    padding: 10px; 
    border: 1px dashed #ccc; 
    font-size: 9pt; 
}
.terms h4 { margin: 0 0 5px 0; color: #666; }
.tax-summary { font-size: 8pt; color: #666; margin: 5px 0; }
.signature-row { 
    display: flex; 
    justify-content: space-between; 
    margin-top: 40px; 
}
.signature-box { width: 200px; text-align: center; }
.signature-box .line { border-top: 1px solid #333; margin-top: 30px; padding-top: 5px; font-size: 9pt; }

.timesheet-header { background: #f0f4f8; padding: 10px; border-left: 4px solid #247DBD; margin: 10px 0; }
.rate-info { font-size: 8pt; color: #666; margin: 5px 0; }
